import React, { useState, useEffect, useMemo } from 'react';
import Header from './components/Header';
import Flashcards from './components/Flashcards';
import Quiz from './components/Quiz';
import QuestionList from './components/QuestionList';
import QuestionBuilder from './components/QuestionBuilder';
import InteractiveAtlas from './components/InteractiveAtlas';
import MobileNavigation from './components/MobileNavigation';
import { AppMode, Question } from './types';

// Import all available chapters
import { questions as ch1 } from './hooks/data_ch1';
import { questions as ch2 } from './hooks/data_ch2';
import { questions as ch3 } from './hooks/data_ch3';
import { questions as ch4 } from './hooks/data_ch4';
import { questions as ch5 } from './hooks/data_ch5';
import { questions as ch6 } from './hooks/data_ch6';
import { questions as ch7 } from './hooks/data_ch7';
import { questions as ch8 } from './hooks/data_ch8';
import { questions as ch9 } from './hooks/data_ch9';
import { questions as ch10 } from './hooks/data_ch10';
import { questions as ch11 } from './hooks/data_ch11';

import { Trash2 } from 'lucide-react';

const App: React.FC = () => {
  const [currentMode, setCurrentMode] = useState<AppMode>(AppMode.FLASHCARDS);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [isHeaderVisible, setIsHeaderVisible] = useState(true);

  const [userVault, setUserVault] = useState<Question[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_ultimate_vault_v5');
      return saved ? JSON.parse(saved) : [];
    } catch (e) { return []; }
  });

  useEffect(() => {
    localStorage.setItem('anatomy_ultimate_vault_v5', JSON.stringify(userVault));
  }, [userVault]);

  // Ensure header is visible when changing modes
  useEffect(() => {
    setIsHeaderVisible(true);
  }, [currentMode]);

  // Final Data Merge Engine
  const allQuestions = useMemo(() => {
    const uniqueQuestions: Question[] = [];
    const seenIds = new Set<string>();

    // 1. Priority to User Vault
    userVault.forEach(q => {
        uniqueQuestions.push(q);
        seenIds.add(q.id);
    });

    // 2. Merge all official sources
    const sources = [
        ...ch1, ...ch2, ...ch3, ...ch4, ...ch5, ...ch6, 
        ...ch7, ...ch8, ...ch9, ...ch10, ...ch11
    ];

    sources.forEach(q => {
        // FILTER: Remove low quality/placeholder questions
        const isLowQuality = 
            q.questionText.includes('Part ') || 
            q.answerText.includes('Node ') || 
            q.questionText.includes('Study Point') ||
            (q.questionText.length < 10 && !q.questionImage);

        if (!seenIds.has(q.id) && !isLowQuality) {
            // Repair missing options
            const finalQ = {
              ...q,
              options: (q.options && q.options.length >= 4) 
                ? q.options 
                : Array.from(new Set([q.answerText, 'Option A', 'Option B', 'Option C', 'Option D'])).slice(0, 4)
            };
            uniqueQuestions.push(finalQ);
            seenIds.add(q.id);
        }
    });

    return uniqueQuestions;
  }, [userVault]);

  const handleEditRequest = (id: string) => {
    setEditingId(id);
    setCurrentMode(AppMode.BUILDER);
  };

  const handleSaveQuestion = (question: Question) => {
    setUserVault(prev => {
        const existingIndex = prev.findIndex(q => q.id === question.id);
        if (existingIndex >= 0) {
            const newVault = [...prev];
            newVault[existingIndex] = question;
            return newVault;
        } else return [question, ...prev];
    });
    setEditingId(null);
    setCurrentMode(AppMode.LIST);
  };

  return (
    <div className="h-[100dvh] w-full flex flex-col bg-slate-50 font-sans text-slate-900 overflow-hidden fixed inset-0">
      {isHeaderVisible && (
        <Header currentMode={currentMode} onModeChange={(m) => { setCurrentMode(m); setEditingId(null); }} />
      )}

      {/* Main Content Area - Added pb-20 on mobile to clear bottom nav */}
      <main className={`flex-1 relative overflow-hidden flex flex-col w-full mx-auto ${isHeaderVisible ? 'max-w-7xl pb-20 md:pb-0' : 'max-w-full'}`}>
        {currentMode === AppMode.FLASHCARDS && (
          <div className="flex-1 h-full animate-in fade-in duration-500">
            <Flashcards data={allQuestions} onEdit={handleEditRequest} />
          </div>
        )}

        {currentMode === AppMode.ATLAS && (
          <div className="flex-1 h-full animate-in slide-in-from-right duration-500">
            <InteractiveAtlas data={allQuestions} />
          </div>
        )}

        {currentMode === AppMode.QUIZ && (
          <div className="flex-1 h-full animate-in zoom-in-95 duration-500">
            <Quiz 
              data={allQuestions} 
              onEdit={handleEditRequest} 
              toggleHeader={setIsHeaderVisible} 
            />
          </div>
        )}

        {currentMode === AppMode.LIST && (
          <div className="flex-1 h-full overflow-y-auto px-3 py-4 custom-scrollbar">
            <QuestionList 
              data={allQuestions} 
              onExport={() => {}} 
              onImport={() => {}} 
              onEdit={handleEditRequest} 
            />
            <div className="flex justify-center p-12">
               <button onClick={() => confirm("Reset all records?") && setUserVault([])} className="text-[10px] font-black text-rose-300 uppercase tracking-widest hover:text-rose-500 transition-colors">
                 <Trash2 size={12} className="inline mr-1" /> Factory Reset Anatomy Vault
               </button>
            </div>
          </div>
        )}

        {currentMode === AppMode.BUILDER && (
          <div className="flex-1 h-full overflow-y-auto custom-scrollbar">
            <QuestionBuilder allQuestions={allQuestions} editingId={editingId} onSave={handleSaveQuestion} onCancel={() => { setEditingId(null); setCurrentMode(AppMode.LIST); }} existingCategories={[]} />
          </div>
        )}
      </main>

      {/* New Mobile Bottom Navigation */}
      <MobileNavigation 
        currentMode={currentMode} 
        onModeChange={(m) => { setCurrentMode(m); setEditingId(null); }}
        isVisible={isHeaderVisible}
      />
    </div>
  );
};

export default App;

// ... existing imports
import React, { useState, useEffect, useMemo } from 'react';
import { Question, QuizQuestion } from '../types';
import { 
  X, Clock, ChevronLeft, ChevronRight, 
  LayoutGrid, Zap, Layers, 
  CheckCircle2, FileText, Flag, List, Image as ImageIcon,
  AlertCircle, Shuffle, Filter, Check, Volume2
} from 'lucide-react';
import { useSpeech } from '../hooks/useSpeech';

// Enhanced Image Handling via Global CDN/Proxy for Speed & Formatting
const cleanImageUrl = (url: string) => {
  if (!url) return '';
  let clean = url;
  // Fix double URL issue if present
  if (url.includes('http') && url.lastIndexOf('http') > 0) {
    clean = url.substring(url.lastIndexOf('http'));
  }
  // Route through wsrv.nl for optimization, caching, and CORS handling
  // w=800: Resize to decent width
  // q=75: Compress quality
  // output=webp: Use modern format
  return `https://wsrv.nl/?url=${encodeURIComponent(clean)}&w=800&q=75&output=webp&il`;
};

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

interface QuizProps {
  data: Question[];
  onEdit?: (id: string) => void;
  toggleHeader?: (visible: boolean) => void;
}

const Quiz: React.FC<QuizProps> = ({ data, onEdit, toggleHeader }) => {
  const [view, setView] = useState<'setup' | 'playing' | 'results' | 'review'>('setup');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);
  const [imgError, setImgError] = useState(false);

  // Setup State
  const [mode, setMode] = useState<'exam' | 'practice' | 'cards'>('exam');
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [questionCount, setQuestionCount] = useState(25);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false); // Default closed on mobile
  const [isShuffle, setIsShuffle] = useState(true);
  const [showDiagramsOnly, setShowDiagramsOnly] = useState(false);
  const [isBankModalOpen, setIsBankModalOpen] = useState(false);

  const { speak, isSpeaking, cancel } = useSpeech();

  const [mistakesVault, setMistakesVault] = useState<string[]>(() => {
    const saved = localStorage.getItem('anatomy_mistakes_v5');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('anatomy_mistakes_v5', JSON.stringify(mistakesVault));
  }, [mistakesVault]);

  useEffect(() => {
    return () => {
      toggleHeader?.(true);
      cancel();
    };
  }, []);

  // Open sidebar by default only on large screens
  useEffect(() => {
    const handleResize = () => {
        if (window.innerWidth >= 1024) {
            setIsSidebarOpen(true);
        } else {
            setIsSidebarOpen(false);
        }
    };
    // Set initial state
    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // --- TIMER LOGIC ---
  useEffect(() => {
    let timer: any;
    if (view === 'playing' && mode === 'exam') {
      if (timeLeft <= 0) {
        handleFinish();
        return;
      }
      timer = setInterval(() => {
        setTimeLeft((prev) => prev - 1);
      }, 1000);
    }
    return () => {
      if (timer) clearInterval(timer);
    };
  }, [timeLeft, view, mode]);

  useEffect(() => {
    cancel(); // Stop audio when changing questions
  }, [currentQIndex, view]);

  const categories = useMemo(() => {
    return Array.from(new Set(data.map(q => q.category))).sort();
  }, [data]);

  const startSession = () => {
    if (mode === 'cards') {
      alert("Please use the 'Flashcards' tab in the main menu for this mode.");
      return; 
    }

    let pool = data;

    // Filter by Category
    if (selectedCategories.length > 0) {
      pool = pool.filter(q => selectedCategories.includes(q.category));
    }

    // Filter Diagrams
    if (showDiagramsOnly) {
      pool = pool.filter(q => q.questionImage || q.answerImage);
    }

    if (pool.length === 0) {
      alert("No questions found for these settings.");
      return;
    }

    // Shuffle if enabled
    if (isShuffle) {
      pool = [...pool].sort(() => Math.random() - 0.5);
    }

    // Limit by questionCount, but don't crash if pool is smaller
    const actualCount = Math.min(pool.length, questionCount);
    const finalPool = pool.slice(0, actualCount);

    const preparedQuestions = finalPool.map(q => {
      let finalOptions = q.options && q.options.length >= 4 ? [...q.options] : [];

      // Fallback generator for missing options
      if (finalOptions.length < 4) {
        const distractors = data
          .filter(item => item.category === q.category && item.answerText !== q.answerText)
          .map(item => item.answerText)
          .sort(() => Math.random() - 0.5)
          .slice(0, 4 - finalOptions.length);

        finalOptions = Array.from(new Set([q.answerText, ...finalOptions, ...distractors]));

        // Final fallback if still not enough
        while(finalOptions.length < 4) {
           finalOptions.push(`Option ${finalOptions.length + 1}`);
        }
      }

      return {
        id: q.id, data: q,
        options: finalOptions.sort(() => Math.random() - 0.5),
        correctOption: q.answerText, userAnswer: null, isFlagged: false
      } as QuizQuestion;
    });

    setQuestions(preparedQuestions);
    setCurrentQIndex(0);
    // Exam mode = 1 min per question, Practice = Unlimited (just tracking)
    setTimeLeft(preparedQuestions.length * 60); 
    setView('playing');
    setImgError(false);
    toggleHeader?.(false);
  };

  const handleFinish = () => {
    cancel();
    const wrongOnes = questions.filter(q => q.userAnswer && q.userAnswer !== q.correctOption).map(q => q.id);
    const correctOnes = questions.filter(q => q.userAnswer === q.correctOption).map(q => q.id);
    setMistakesVault(prev => {
      const added = Array.from(new Set([...prev, ...wrongOnes]));
      return added.filter(id => !correctOnes.includes(id));
    });
    setView('results');
    toggleHeader?.(true);
  };

  const exitQuiz = () => {
    if (confirm("Abort session? Progress will be lost.")) {
      cancel();
      setView('setup');
      toggleHeader?.(true);
    }
  };

  // --- VIEW: SETUP (Matching the Screenshot) ---
  if (view === 'setup') {
    // Calculate max available questions dynamically
    let filteredPool = data;
    if (selectedCategories.length > 0) {
      filteredPool = filteredPool.filter(q => selectedCategories.includes(q.category));
    }
    if (showDiagramsOnly) {
      filteredPool = filteredPool.filter(q => q.questionImage || q.answerImage);
    }
    const maxQuestions = filteredPool.length;

    // Ensure current count selection is valid
    if (questionCount > maxQuestions && maxQuestions > 0) {
       setQuestionCount(maxQuestions);
    }

    return (
      // Changed: Use proper scrolling container with min-h for flex centering
      <div className="h-full w-full bg-slate-100 overflow-y-auto custom-scrollbar relative">
        <div className="min-h-full w-full flex flex-col items-center justify-center p-4 pb-28 md:pb-12">

          <div className="w-full max-w-md bg-white rounded-3xl shadow-xl overflow-hidden animate-in zoom-in-95 duration-300 border border-slate-200 relative z-10">

             {/* Header - Dark Blue */}
             <div className="bg-[#0f172a] p-6 flex justify-between items-center text-white">
                <div className="flex items-center gap-3">
                   <div className="p-2 bg-white/10 rounded-lg">
                      <LayoutGrid size={20} className="text-rose-500" />
                   </div>
                   <h2 className="text-xl font-bold">Assessment Setup</h2>
                </div>
                <div className="text-right">
                   <div className="text-2xl font-black">{data.length}</div>
                   <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">BANK</div>
                </div>
             </div>

             <div className="p-6 space-y-6">

                {/* Mode Selection Cards */}
                <div className="space-y-3">
                   {/* Exam Card */}
                   <button 
                     onClick={() => setMode('exam')}
                     className={`w-full p-4 rounded-2xl border-2 transition-all flex flex-col items-center justify-center gap-1 ${mode === 'exam' ? 'border-rose-500 bg-rose-50' : 'border-slate-100 hover:border-slate-200'}`}
                   >
                      <Clock size={24} className={mode === 'exam' ? 'text-rose-600' : 'text-slate-400'} />
                      <span className="font-bold text-slate-800 text-sm">Exam</span>
                      <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">TIMED</span>
                   </button>

                   {/* Practice Card */}
                   <button 
                     onClick={() => setMode('practice')}
                     className={`w-full p-4 rounded-2xl border-2 transition-all flex flex-col items-center justify-center gap-1 ${mode === 'practice' ? 'border-blue-500 bg-blue-50' : 'border-slate-100 hover:border-slate-200'}`}
                   >
                      <Zap size={24} className={mode === 'practice' ? 'text-blue-600' : 'text-slate-400'} />
                      <span className="font-bold text-slate-800 text-sm">Practice</span>
                      <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">INSTANT</span>
                   </button>

                   {/* Cards Card (Visual only, redirects) */}
                   <button 
                     onClick={() => setMode('cards')}
                     className={`w-full p-4 rounded-2xl border-2 transition-all flex flex-col items-center justify-center gap-1 ${mode === 'cards' ? 'border-amber-500 bg-amber-50' : 'border-slate-100 hover:border-slate-200'}`}
                   >
                      <Layers size={24} className={mode === 'cards' ? 'text-amber-600' : 'text-slate-400'} />
                      <span className="font-bold text-slate-800 text-sm">Cards</span>
                      <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">MANUAL</span>
                   </button>
                </div>

                {/* Question Bank Select */}
                <div className="space-y-2">
                   <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Question Bank</label>
                   <button 
                     onClick={() => setIsBankModalOpen(true)}
                     className="w-full p-4 bg-white border border-slate-200 rounded-xl flex justify-between items-center shadow-sm hover:border-rose-200 transition-colors"
                   >
                      <div className="flex items-center gap-3">
                         <div className="text-rose-500"><FilterIcon size={18}/></div> 
                         <span className="font-bold text-sm text-slate-700">
                           {selectedCategories.length === 0 ? "All Topics" : `${selectedCategories.length} Chapters Selected`}
                         </span>
                      </div>
                      <ChevronRight size={18} className="text-slate-400" />
                   </button>
                </div>

                {/* Slider (Red Thumb) */}
                <div className="space-y-4">
                   <div className="flex justify-between items-center px-1">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Quantity: {questionCount}</label>
                      <span className="text-[9px] font-bold text-slate-400 bg-slate-100 px-2 py-1 rounded">Max Available: {maxQuestions}</span>
                   </div>
                   <input 
                     type="range" 
                     min="1" 
                     max={maxQuestions || 1} 
                     step="1"
                     value={questionCount}
                     disabled={maxQuestions === 0}
                     onChange={(e) => setQuestionCount(Number(e.target.value))}
                     className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-[#e11d48] disabled:opacity-50"
                   />
                </div>

                {/* Toggles Row */}
                <div className="flex gap-3">
                   <button 
                     onClick={() => setShowDiagramsOnly(!showDiagramsOnly)}
                     className={`flex-1 py-3 rounded-xl border font-bold text-[10px] uppercase tracking-wider flex items-center justify-center gap-2 transition-all ${showDiagramsOnly ? 'bg-slate-800 text-white border-slate-800' : 'bg-white text-slate-500 border-slate-200'}`}
